def add_translations():
    path = "app/src/main/java/com/anesthesiaclinic/anesthesiabriefs/utils/TranslationHelper.kt"
    if not os.path.exists(path):
        print(f"File not found: {path}")
        return
        
    print(f"Reading: {path}")
    with open(path) as f:
        content = f.read()
        
    # We find 'private val trToEnDictionary = mapOf('
    marker = "private val trToEnDictionary = mapOf("
    idx = content.find(marker)
    if idx == -1:
        print("Marker not found!")
        return
        
    # We will insert our new translations right after the mapOf(
    insert_pos = idx + len(marker)
    
    # Format new translation lines
    lines = []
    for tr, en in translations.items():
        # Escape quotes in keys and values
        tr_esc = tr.replace('"', '\\"')
        en_esc = en.replace('"', '\\"')
        # We only add if it's not already in the dictionary
        if f'"{tr_esc}" to' not in content:
            lines.append(f'        "{tr_esc}" to "{en_esc}",')
            
    if not lines:
        print("No new translations to add.")
        return
        
    print(f"Adding {len(lines)} new translation lines.")
    new_content = content[:insert_pos] + "\n" + "\n".join(lines) + content[insert_pos:]
    
    with open(path, 'w') as f:
        f.write(new_content)
    print("TranslationHelper.kt updated successfully!")

if __name__ == "__main__":
    add_translations()
